### Modified: `provider.go`

```go
package bestiary

// Provider identifies the organization that hosts or publishes an AI model.
type Provider string

// ProviderLocal is a bestiary-specific provider for locally-hosted models.
// It is not derived from the models.dev API.
const ProviderLocal Provider = "local"

// knownProviders is built at init time: all generated providers + ProviderLocal.
var knownProviders []Provider

func init() {
    knownProviders = make([]Provider, len(generatedProviders)+1)
    copy(knownProviders, generatedProviders[:])
    knownProviders[len(generatedProviders)] = ProviderLocal
}

// IsKnown reports whether p is a recognized Provider (any API provider or ProviderLocal).
func (p Provider) IsKnown() bool {
    for _, known := range knownProviders {
        if p == known {
            return true
        }
    }
    return false
}

// Providers returns all known Provider values. The returned slice is a
// defensive copy — modifying it does not affect the package state.
func Providers() []Provider {
    out := make([]Provider, len(knownProviders))
    copy(out, knownProviders)
    return out
}

// String, MarshalText, UnmarshalText — unchanged.
```

### New: `modelref.go`

```go
package bestiary

// ModelRef represents the canonical identity of a model as a 4-tuple.
// It decomposes a ModelInfo into (Provider, Family, Variant, Date) for
// cross-provider comparison and entity normalization.
//
// The Family and Variant fields are derived from the models.dev API's
// "family" field, which conflates both concepts (e.g., "claude-opus" is
// family="claude", variant="opus"). The decomposition is best-effort
// until a normalization pipeline is implemented.
//
// For now, RawFamily stores the API family field verbatim, and Family/Variant
// are empty strings. Future epochs will populate them via normalization.
type ModelRef struct {
    Provider  Provider // Hosting provider
    RawFamily string   // API family field verbatim (e.g., "claude-opus")
    Family    string   // Normalized family (e.g., "claude") — empty until normalization epoch
    Variant   string   // Normalized variant (e.g., "opus") — empty until normalization epoch
    Date      string   // Release date from model ID or ReleaseDate field, if present
}

// Ref returns a ModelRef for this ModelInfo.
// Family and Variant are empty pending normalization pipeline.
// RawFamily is the API family field. Date is the ReleaseDate field.
func (m ModelInfo) Ref() ModelRef {
    return ModelRef{
        Provider:  m.Provider,
        RawFamily: m.Family,
        Date:      m.ReleaseDate,
    }
}

// ModelsByRawFamily returns all static models whose API family field matches
// the given value, across all providers. This is the cross-provider query
// using the raw (un-decomposed) family field.
func ModelsByRawFamily(family string) []ModelInfo {
    var out []ModelInfo
    for _, m := range staticModels {
        if m.Family == family {
            out = append(out, m)
        }
    }
    return out
}

// ProvidersForRawFamily returns the set of providers that host models with
// the given raw family string. Useful for answering "who hosts claude-opus?"
func ProvidersForRawFamily(family string) []Provider {
    seen := make(map[Provider]struct{})
    var out []Provider
    for _, m := range staticModels {
        if m.Family == family {
            if _, ok := seen[m.Provider]; !ok {
                seen[m.Provider] = struct{}{}
                out = append(out, m.Provider)
            }
        }
    }
    return out
}
```

