### Modified: `modelref.go`

```go
type ModelRef struct {
    Provider  Provider
    RawFamily Family
    Family    Family   // populated via decomposition (was empty)
    Variant   string   // populated via decomposition (was empty)
    Date      string   // populated from ReleaseDate or extracted from ID
}

// Ref returns a fully-populated ModelRef.
// Family/Variant are decomposed from RawFamily; Date prefers ReleaseDate
// then falls back to date extraction from model ID.
func (m ModelInfo) Ref() ModelRef {
    fam, variant := DecomposeFamily(m.Family)
    return ModelRef{
        Provider:  m.Provider,
        RawFamily: m.Family,
        Family:    fam,
        Variant:   variant,
        Date:      ExtractDate(m.ID, m.ReleaseDate),
    }
}

// Canonical returns the canonical triple (Family, Variant, Date) — the
// provider-independent identity.
func (r ModelRef) Canonical() Canonical {
    return Canonical{Family: r.Family, Variant: r.Variant, Date: r.Date}
}

// Designations returns all known aliases for this model across providers.
// Each Designation has Rating = AcceptabilityAdmitted in this epoch.
func (r ModelRef) Designations() []Designation { /* ... */ }
```

