type CanonicalScheme int

const (
    SchemeDefault     CanonicalScheme = iota // family/variant@date
    SchemeHuggingFace                        // family-variant@date
    SchemePURL                               // pkg:huggingface/provider/family-variant@date
    SchemeRaw                                // raw API model ID
)

func (s CanonicalScheme) String() string
func (s CanonicalScheme) IsValid() bool
