### `modelref.go` (revised)

```go
package bestiary

// ModelRef is the canonical reference for a model.
// Family/Variant/Date are populated at codegen time for static models;
// at runtime via Resolve() for user input.
type ModelRef struct {
    Provider  Provider
    RawFamily Family   // verbatim API family field
    Family    Family   // normalized family
    Variant   string   // normalized variant
    Date      string   // YYYY-MM-DD or empty
}

// String implements fmt.Stringer using SchemeDefault.
func (r ModelRef) String() string { return r.Format(SchemeDefault) }

// Format renders the ModelRef in the requested scheme.
//
// Examples for ModelRef{Provider:"anthropic", Family:"claude", Variant:"opus", Date:"2025-05-14"}:
//   r.Format(SchemeDefault)     → "claude/opus@2025-05-14"
//   r.Format(SchemeHuggingFace) → "claude-opus@2025-05-14"
//   r.Format(SchemePURL)        → "pkg:huggingface/anthropic/claude-opus@2025-05-14"
//   r.Format(SchemeRaw)         → "claude-opus-4-20250514"  (resolved from ModelInfo.ID)
func (r ModelRef) Format(scheme CanonicalScheme) string

// Designations returns all known aliases for this canonical model
// across providers. Each Designation is AcceptabilityAdmitted (this epoch).
func (r ModelRef) Designations() []Designation

// Ref returns the ModelRef for this ModelInfo. Pure projection — no
// decomposition logic at runtime (decomp baked in at codegen).
func (m ModelInfo) Ref() ModelRef {
    return ModelRef{
        Provider:  m.Provider,
        RawFamily: m.Family,
        Family:    m.NormalizedFamily,    // NEW field on ModelInfo, populated by codegen
        Variant:   m.NormalizedVariant,   // NEW field on ModelInfo
        Date:      m.NormalizedDate,      // NEW field on ModelInfo
    }
}
```

### `resolve.go`

```go
package bestiary

// ResolveOption customises Resolve behaviour.
type ResolveOption interface{ apply(*resolveOpts) }

// WithScheme pins the scheme for input parsing (overrides auto-detect).
func WithScheme(s CanonicalScheme) ResolveOption

// Resolve parses any model expression and returns matching ModelRefs.
//
// Auto-detection rules (when no WithScheme option):
//   - starts with "pkg:" → SchemePURL
//   - contains "/"        → SchemeDefault
//   - matches a known raw API ID → SchemeRaw
//   - else → SchemeHuggingFace
//
// Returns:
//   - ErrNotFound — input parses but no model matches
//   - ErrAmbiguous (with .Candidates field) — multiple matches; user should narrow
//   - nil — one or more matches; if >1 and disambiguation isn't required by caller,
//     they get all matches (e.g., for cross-provider lookups).
func Resolve(input string, opts ...ResolveOption) ([]ModelRef, error)

// ErrAmbiguous wraps a slice of candidate refs.
type ErrAmbiguous struct {
    Input      string
    Candidates []ModelRef
}

func (e *ErrAmbiguous) Error() string  // "ambiguous: <input> matches N models — try --scheme=<...> or include provider"
```

